/**
 * Подтема PlasmaSdServiceTheme.Inverse
 */
@Composable
public fun PlasmaSdServiceTheme.Inverse(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable () -> Unit,
) {
    val currentColors = LocalPlasmaSdServiceColors.current
    val overrideColors = currentColors.copyAttrs(InverseColorsOverride)
    val currentGradients = LocalPlasmaSdServiceGradients.current
    val overrideGradients = currentGradients.copyAttrs(InverseGradientsOverride)
    PlasmaSdServiceTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
